use std::convert::TryInto;

struct DataRecord {
    id: u32,
    data_checksum: u64,
    payload: Vec<u8>,
}

impl DataRecord {
    fn new(id: u32, checksum: u64, payload: Vec<u8>) -> Self {
        DataRecord { id, data_checksum: checksum, payload }
    }
}

fn validate_record(record: &DataRecord) -> bool {
    if record.data_checksum == 0 { return false; }
    let calculated_checksum = record.payload.iter().fold(0u64, |acc, &byte| acc.wrapping_add(byte as u64));
    calculated_checksum == record.data_checksum && !record.payload.is_empty()
}

fn filter_valid_records(input_records: Vec<DataRecord>) -> Vec<DataRecord> {
    let mut valid_records = Vec::new();
    for record in input_records.into_iter() {
        if validate_record(&record) {
            valid_records.push(record);
        }
    }
    valid_records
}

fn main() {
    let bad_record = DataRecord::new(101, 999u64, vec![0xAA, 0xBB]);
    let good_record = DataRecord::new(202, 0x0000000000000066, vec![0xCC, 0xDD]);
    let empty_payload_record = DataRecord::new(303, 1u64, vec![]);

    let input_data = vec![bad_record, good_record, empty_payload_record];

    let results = filter_valid_records(input_data);

    println!("Found {} valid records.", results.len());
    for record in results {
        println!("Valid ID: {}", record.id);
    }
}

use std::collections::HashMap;
use chrono::{DateTime, Utc};

struct InteractionLog {
    timestamp: DateTime<Utc>,
    user_id: String,
    item_viewed: String,
}

fn compute_feature_vector(logs: Vec<InteractionLog>, user_id: &str) -> Option<Vec<String>> {
    let mut recent_views: std::collections::BTreeSet<String> = std::collections::BTreeSet::new();
    let time_window_start: DateTime<Utc> = Utc::now() - chrono::Duration::days(30);

    let filtered_logs: Vec<&InteractionLog> = logs.iter()
        .filter(|log| log.user_id == user_id && log.timestamp >= time_window_start)
        .collect();

    for log in filtered_logs.into_iter().rev(){
        if recent_views.len() < 10 {
            recent_views.insert(log.item_viewed.clone());
        }
    }

    let mut vector: Vec<String> = recent_views.into_iter().collect();
    vector.sort_by(|a, b| a.cmp(b).reverse());
    Some(vector)
}

use std::fs::File;
use std::io::{self, Read};

struct BinaryValidator {
    file_path: String,
}

impl BinaryValidator {
    fn new(file_path: String) -> Self {
        BinaryValidator { file_path }
    }

    fn validate(&self) -> io::Result<bool> {
        let mut file = File::open(&self.file_path)?;
        let mut buffer = Vec::new();
        file.read_to_end(&mut buffer)?;

        if buffer.len() < 4 {
            return Ok(false);
        }

        let magic_bytes: [u8; 4] = buffer[0..4].try_into().unwrap();

        let elf_magic: [u8; 4] = [0x7f, 0x65, 0x4c, 0x46];

        if magic_bytes == elf_magic {
            Ok(true)
        } else {
            Ok(false)
        }
    }
}

fn main() -> io::Result<()> {
    let validator = BinaryValidator::new("path/to/a/binary.elf".to_string());
    match validator.validate() {
        Ok(is_valid) => {
            if is_valid {
                println!("File seems structurally valid for execution.");
            } else {
                println!("Warning: File format does not match expected standard.");
            }
        },
        Err(e) => {
            eprintln!("Failed to process file: {}", e);
        }
    }
    Ok(())
}

use std::collections::HashSet;
use rand::prelude::*;

#[derive(Clone, Debug)]
struct Process {
    id: u32,
    name: String,
}

impl Process {
    fn new(id: u32, name: &str) -> Self {
        Process { id, name: name.to_string() }
    }

    fn is_running(&self) -> bool {
        true
    }
}

fn main() {
    let mut all_processes: Vec<Process> = vec![
        Process::new(101, "web-server"),
        Process::new(205, "database-worker"),
        Process::new(310, "api-gateway"),
        Process::new(400, "cache-service"),
    ];

    let mut rng = rand::thread_rng();
    let num_to_kill = 2;

    println!("System initialized with {} processes.", all_processes.len());

    let processes_to_kill: HashSet<u32> = (0..num_to_kill)
        .map(|_| rng.gen_range(0..all_processes.len() as u32))
        .collect();

    let mut active_processes: Vec<Process> = Vec::new();

    for i in 0..all_processes.len() {
        if processes_to_kill.contains(&(i as u32)) {
            println!("!!! CRASH DETECTED: Killing process {} ({}) during stress test.", all_processes[i].id, all_processes[i].name);
        } else {
            active_processes.push(all_processes[i].clone());
        }
    }

    println!("nSimulation complete. {} processes remain active.", active_processes.len());
}

use std::collections::HashMap;
use std::fs::File;
use std::io::{self, Read};
use std::path::Path;

struct AppConfig {
    settings: HashMap<String, String>,
}
impl Default for AppConfig {
    fn default() -> Self {
        AppConfig { settings: HashMap::new() }
    }
}
impl AppConfig {
    fn load_from_file(path: &Path) -> io::Result<Self> {
        let mut file = File::open(path)?;
        let mut contents = String::new();
        file.read_to_string(&mut contents)?;
        let mut settings = HashMap::new();
        for line in contents.lines() {
            let trimmed = line.trim();
            if !trimmed.is_empty() && !trimmed.starts_with('#') {
                if let Some((key, value)) = trimmed.split_once('=') {
                    settings.insert(key.trim().to_string(), value.trim().to_string());
                }
            }
        }
        Ok(AppConfig { settings })
    }
}

fn main() -> io::Result<()> {
    let config_path = Path::new("app_settings.toml");
    std::fs::write(config_path, "# Application Settings #nserver_ip=127.0.0.1nport=8080nenabled=true");

    let mut current_config = AppConfig::load_from_file(config_path)?;
    println!("Initial Load Successful: {:?}", current_config.settings);

    loop {
        std::thread::sleep(std::time::Duration::from_secs(2));
        match AppConfig::load_from_file(config_path) {
            Ok(new_config) => {
                if new_config.settings != current_config.settings {
                    println!("n--- Detected Change ---");
                    println!("Successfully reloaded settings: {:?}", new_config.settings);
                    current_config = new_config;
                } else {
                    print!(".");
                }
            }
            Err(e) => {
                eprintln!("Error reading config file: {}", e);
            }
        }
    }
}
